"use client";

import React, { useState } from 'react';
import { searchDrugs, syncDrugs } from '@/util/drugApi'; // API 경로 확인 필요
import './drug.module.css'

// ⭐️ (선택사항) 약품 데이터의 타입을 미리 정의해두면 자동완성이 되어 편합니다.
// 지금은 간단하게 any로 처리하거나 아래처럼 인터페이스를 만들 수 있습니다.
interface Drug {
  itemSeq: string;
  itemName: string;
  entpName: string;
  efficacy: string;
  itemImage: string | null;
}

export default function DrugPage() {
    const [keyword, setKeyword] = useState<string>("");
    
    // ⭐️ 수정됨: 빈 배열([])만 쓰면 타입스크립트가 뭔지 몰라 에러가 날 수 있습니다.
    // <any[]> 혹은 위에서 만든 <Drug[]>를 붙여줍니다.
    const [drugs, setDrugs] = useState<any[]>([]); 
    
    const [loading, setLoading] = useState<boolean>(false);
    const [message, setMessage] = useState<string>("");

    const [page, setPage] = useState<number>(0);
    const [totalPages, setTotalPages] = useState<number>(0);

    // ⭐️ 수정됨: 매개변수 뒤에 : string, : number 타입을 명시했습니다.
    const fetchDrugs = async (searchKeyword: string, searchPage: number) => {
        setLoading(true);
        setMessage("데이터를 불러오는 중...");
        try {
            const data = await searchDrugs(searchKeyword, searchPage, 10);
            
            setDrugs(data.content);
            setTotalPages(data.totalPages);
            setPage(data.number);

            if(data.totalElements === 0) {
                setMessage("검색 결과가 없습니다.");
            } else {
                setMessage("");
            }
        } catch (err) {
            setMessage("오류가 발생했습니다.");
            setDrugs([]);
        } finally {
            setLoading(false);
        }
    };

    // 이벤트 객체 타입 (React.FormEvent)
    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        if (!keyword.trim()) return;
        setPage(0);
        fetchDrugs(keyword, 0);
    };

    const handlePageChange = (newPage: number) => {
        if (newPage >= 0 && newPage < totalPages) {
            fetchDrugs(keyword, newPage);
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const handleSync = async () => {
        if (!confirm("데이터 동기화를 시작하시겠습니까? (시간이 소요됩니다)")) return;
        setLoading(true);
        setMessage("동기화 진행 중...");
        try {
            const resultMsg = await syncDrugs();
            setMessage("✅ " + resultMsg);
        } catch (err) {
            setMessage("❌ 동기화 실패");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container">
            <h1 className="title">e약은요 검색</h1>

            <div className="searchBox">
                <form onSubmit={handleSearch} style={{ display: 'flex', width: '100%', gap: '10px', justifyContent: 'center' }}>
                    <input
                        type="text"
                        className="input"
                        placeholder="증상이나 약 이름을 입력하세요 (예: 두통)"
                        value={keyword}
                        onChange={(e) => setKeyword(e.target.value)}
                    />
                    <button type="submit" className="btn" disabled={loading}>
                        검색
                    </button>
                </form>
                <button onClick={handleSync} className="btn sync" disabled={loading}>
                    {loading ? "작업 중..." : "전체 동기화"}
                </button>
            </div>

            {message && <div className="message">{message}</div>}

            {!loading && drugs.length > 0 && (
                <div className="grid">
                    {/* drug 타입도 any로 추론되거나 인터페이스를 따릅니다 */}
                    {drugs.map((drug: any) => (
                        <div key={drug.itemSeq} className="card">
                            <div className="imgWrapper">
                                {drug.itemImage ? (
                                    <img src={drug.itemImage} alt={drug.itemName} />
                                ) : (
                                    <span style={{ color: '#ccc' }}>이미지 없음</span>
                                )}
                            </div>
                            <div className="content">
                                <span className="company">{drug.entpName}</span>
                                <h3 className="drugName">{drug.itemName}</h3>
                                <p className="info">
                                    <strong>효능:</strong> {drug.efficacy}
                                </p>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {!loading && drugs.length > 0 && (
                <div className="pagination-container">
                    <button 
                        className="page-btn"
                        onClick={() => handlePageChange(page - 1)}
                        disabled={page === 0}
                    >
                        &lt; 이전
                    </button>
                    
                    <span className="page-info">
                        Page <span className="current-page">{page + 1}</span> of {totalPages}
                    </span>

                    <button 
                        className="page-btn"
                        onClick={() => handlePageChange(page + 1)}
                        disabled={page >= totalPages - 1}
                    >
                        다음 &gt;
                    </button>
                </div>
            )}
        </div>
    );
}